    knowledge: [
      { tab: "Liturgical Year", intro: "The Church lives each year as a journey through the life of Christ — from expectation, through birth and passion, to resurrection.", cards: [
        { icon: "🕯", title: "Advent", text: "Four weeks of joyful expectation of the Saviour's coming. The season of the Advent wreath and dawn Masses in honour of Mary." },
        { icon: "⭐", title: "Christmas", text: "Celebrating the birth of Jesus in Bethlehem. The season lasts until the Baptism of the Lord, with Midnight Mass at its heart." },
        { icon: "✝", title: "Lent", text: "Forty days of conversion, prayer, fasting and almsgiving — from Ash Wednesday to Holy Thursday." },
        { icon: "🌅", title: "Easter", text: "The Resurrection of the Lord — the greatest Christian feast. Paschal joy lasts fifty days, until Pentecost." },
        { icon: "🌿", title: "Ordinary Time", text: "A time of growing in faith day by day. Its green colour symbolises hope and life." },
      ]},
      { tab: "Sacraments", intro: "The seven sacraments are visible signs of invisible grace, accompanying a person from birth to the end of the earthly journey.", cards: [
        { icon: "💧", title: "Baptism", text: "The gateway to life in the Spirit — washing away original sin and joining the community of the Church." },
        { icon: "🔥", title: "Confirmation", text: "Strengthening with the gifts of the Holy Spirit for a mature and courageous witness of faith." },
        { icon: "🍞", title: "Eucharist", text: "The source and summit of Christian life — the real presence of Christ under the forms of bread and wine." },
        { icon: "🕊", title: "Penance", text: "The sacrament of mercy — reconciliation with God and the Church through the confession of sins." },
        { icon: "🙌", title: "Anointing of the Sick", text: "Strength and comfort for the suffering and ill — a sign of God's closeness in weakness." },
        { icon: "💍", title: "Matrimony", text: "The covenant of a man and a woman — an image of Christ's love for the Church." },
        { icon: "⛪", title: "Holy Orders", text: "The sacrament of service — a mission to teach, sanctify and shepherd God's people." },
      ]},
      { tab: "Angels", intro: "“For He will command His angels concerning you, to guard you in all your ways” (Psalm 91:11).", cards: [
        { icon: "👑", title: "Seraphim & Cherubim", text: "Closest to God's throne. The seraphim burn with love (“Holy, Holy, Holy” — Isaiah 6); the cherubim guard God's glory." },
        { icon: "🛡", title: "Michael — “Who is like God?”", text: "Commander of the heavenly hosts, vanquisher of evil, patron of soldiers and defender of the Church." },
        { icon: "📯", title: "Gabriel — the Messenger", text: "He announced the birth of Jesus to Mary. His name means “God is my strength”. Patron of messengers and diplomats." },
        { icon: "🌿", title: "Raphael — the Healer", text: "“God heals” — Tobias's companion on his journey, patron of travellers, the sick and physicians." },
        { icon: "👼", title: "Guardian Angels", text: "Tradition holds that every person has an angel who protects and guides them. Their feast day is 2 October." },
      ]},
      { tab: "Saints", daily: true, intro: "Friends of God who show that holiness is possible at any age and in every era. Each day one of them is the patron of this site.", cards: [
        { icon: "✝", title: "St. John Paul II (1920–2005)", text: "Karol Wojtyła from Wadowice, pope for 27 years. He helped bring down communism and told the world: “Be not afraid!”. He founded World Youth Day and established Divine Mercy Sunday. Canonized in 2014." },
        { icon: "💗", title: "St. Faustina Kowalska (1905–1938)", text: "A humble Polish nun to whom Jesus dictated the message of Divine Mercy and the Chaplet. Her “Diary” is among the most translated Polish books. She died of tuberculosis at 33." },
        { icon: "🎓", title: "St. Dominic Savio (1842–1857)", text: "A pupil of St. John Bosco who died at just 14. His motto: “Death rather than sin”. Patron of altar servers and young people." },
        { icon: "🕯", title: "Bl. Jerzy Popiełuszko (1947–1984)", text: "Chaplain of the Solidarity movement who preached: “Overcome evil with good”. Murdered by the communist secret police in 1984; beatified in 2010. Millions of pilgrims have visited his grave in Warsaw." },
        { icon: "💻", title: "St. Carlo Acutis (1991–2006)", text: "A teenage computer programmer from Milan, called “God's influencer”. He built an online exhibition of Eucharistic miracles. He died of leukaemia at 15 and was canonized in 2025 as the first millennial saint." },
        { icon: "🌿", title: "St. Francis of Assisi (c. 1181–1226)", text: "A rich merchant's son who chose radical poverty. Creator of the first nativity scene and author of the “Canticle of the Sun”. Patron of ecology and animals." },
        { icon: "🔥", title: "St. Maximilian Kolbe (1894–1941)", text: "A Franciscan friar, missionary and publisher. In Auschwitz he voluntarily gave his life for a fellow prisoner, a father of a family. Patron of difficult times." },
        { icon: "🌹", title: "St. Thérèse of Lisieux (1873–1897)", text: "A Carmelite nun and author of the “little way” — holiness in everyday small things. She died at 24; Doctor of the Church and patroness of the missions." },
        { icon: "🙌", title: "St. Padre Pio (1887–1968)", text: "An Italian Capuchin and stigmatic who heard confessions for hours. He founded the “Home for the Relief of Suffering” hospital. He used to say: “Pray, hope and don't worry”." },
        { icon: "🔎", title: "St. Anthony of Padua (1195–1231)", text: "A brilliant preacher and Doctor of the Church. Patron of lost things — for centuries people have asked his help in finding them." },
      ]},
    ],
    facts: [
      { icon: "📖", title: "Bestseller of all time", text: "The Bible is the most published book in the world — translated in whole or in part into more than 3,600 languages." },
      { icon: "🐟", title: "The secret sign of the fish", text: "The Greek word ICHTHYS (fish) is an acrostic: “Jesus Christ, Son of God, Saviour”. The fish was a secret sign of the first Christians." },
      { icon: "🙏", title: "Amen — so be it", text: "The word “Amen” comes from Hebrew and means “truly, so be it”. It sounds almost identical in hundreds of languages." },
      { icon: "🕯", title: "The catacombs of Rome", text: "The underground corridors where the first Christians prayed and buried their dead stretch for over 150 kilometres beneath Rome." },
      { icon: "😭", title: "The shortest verse", text: "The shortest verse in the Bible is “Jesus wept” (John 11:35) — two words showing how close God is to human pain." },
      { icon: "🎄", title: "Where does the Christmas tree come from?", text: "The custom of decorating a tree arose in German lands in the 16th century — the evergreen symbolises eternal life." },
      { icon: "⛪", title: "The oldest hymn", text: "“Phos Hilaron” (O Gladsome Light) has been sung continuously since the 3rd century — the oldest Christian hymn still in use." },
      { icon: "🔔", title: "The Angelus three times a day", text: "Church bells traditionally ring at 6 am, noon and 6 pm, calling the faithful to the Angelus prayer — a custom dating back to the 13th century." },
    ],
